The Angular 18 Signal Implementation 💻

To ensure real-time rendering as the user types without lag, I used Angular’s reactive computed signals. It automatically handles the conditional logic for male vs. female parameters:

bodyFat = computed(() => {
const g = this.gender();
const h = this.height();
const w = this.waist();
const n = this.neck();
const hip = this.hip();
if (h <= 0 || w <= 0 || n <= 0) return 0;
let result = 0;
if (g === 'male') {
result = 495 / (1.0324 - 0.19077 * Math.log10(w - n) + 0.15456 * Math.log10(h)) - 450;
} else {
result = 495 / (1.29579 - 0.35004 * Math.log10(w + hip - n) + 0.221 * Math.log10(h)) - 450;
}
return Math.max(2, Math.min(60, result));
});

